import express from "express";
import path from "path";
import { createServer as createViteServer } from "vite";
import { GoogleGenAI } from "@google/genai";
import dotenv from "dotenv";
import { createClient } from "@supabase/supabase-js";

// Load environment variables
dotenv.config();

// Suppress noisy SDK internal warnings about non-text parts (toolCall/toolResponse).
// These are expected when using function calling and googleSearch grounding;
// we handle all content manually via candidates[0].content.parts.
const _origConsoleLog = console.log;
console.log = (...args: any[]) => {
  if (
    args.length > 0 &&
    typeof args[0] === "string" &&
    args[0].includes("non-text parts") &&
    args[0].includes("returning concatenation")
  ) {
    return; // suppress
  }
  _origConsoleLog(...args);
};

async function startServer() {
  const app = express();
  const PORT = 3000;

  // Middleware for parsing JSON with generous limits
  app.use(express.json({ limit: "50mb" }));

  // Lazy-loaded Gemini API Client
  let aiClient: GoogleGenAI | null = null;
  function getGeminiClient(userApiKey?: string) {
    if (userApiKey) {
      return new GoogleGenAI({
        apiKey: userApiKey,
        httpOptions: {
          timeout: 300000,
          headers: { "User-Agent": "aistudio-build" },
        },
      });
    }

    if (!aiClient) {
      const apiKey = process.env.GEMINI_API_KEY;
      if (!apiKey) {
        throw new Error("גילוי שגיאה: מפתח ה-API של Gemini חסר במערכת. יש להגדיר אותו בהגדרות הסודות.");
      }
      aiClient = new GoogleGenAI({
        apiKey,
        httpOptions: {
          timeout: 300000, // Increase timeout to 300s (5 minutes) for deep research/grounding
          headers: {
            "User-Agent": "aistudio-build",
          },
        },
      });
    }
    return aiClient;
  }

  // Helper to map Gemini errors to meaningful status codes
  function mapErrorToStatus(error: any): number {
    const errStr = (error.toString() + " " + JSON.stringify(error)).toLowerCase();
    if (errStr.includes("deadline") || errStr.includes("timeout") || errStr.includes("504") || error.status === "DEADLINE_EXCEEDED") {
      return 504;
    }
    if (errStr.includes("resource_exhausted") || errStr.includes("429") || error.status === "RESOURCE_EXHAUSTED") {
      return 429;
    }
    return 500;
  }

  // API Route for Sefaria Source Explanation chat (Yeshivish style)
  app.post("/api/chat", async (req, res) => {
    try {
      const { message, history = [], model = "gemini-3.5-flash", sourceRef, sourceContent, isGemara, apiKey } = req.body;
      const ai = getGeminiClient(apiKey);
      
      let contextInfo = `המקור הנלמד: ${sourceRef || "לא צוין"}\nתוכן המקור:\n${sourceContent || "לא צוין"}`;
      
      // Heuristic for Rashi: If isGemara is true OR it looks like a talmud ref
      if (isGemara || (sourceRef && (sourceRef.includes(".") || sourceRef.match(/[א-ת]+\s[א-ת][\"״׳]\s[א-ב]/)))) {
        try {
          // Normalize ref for Rashi lookup: Rashi_on_Berakhot.2a
          const normalizedRef = String(sourceRef).replace(/\s+/g, "_").replace(/,/g, ".");
          const rashiRef = `Rashi_on_${normalizedRef}`;
          const rashiUrl = `https://www.sefaria.org/api/texts/${encodeURIComponent(rashiRef)}?context=0`;
          
          const controller = new AbortController();
          const timeoutId = setTimeout(() => controller.abort(), 8000);
          
          try {
            const rashiRes = await fetch(rashiUrl, { signal: controller.signal });
            if (rashiRes.ok) {
              const rashiData = await rashiRes.json();
              if (rashiData && rashiData.he && (!Array.isArray(rashiData.he) || rashiData.he.length > 0)) {
                const rashiText = Array.isArray(rashiData.he) ? rashiData.he.flat(Infinity).join("\n") : rashiData.he;
                if (rashiText.trim().length > 0) {
                  contextInfo += `\n\nפירוש רש"י על הקטע:\n${rashiText}`;
                  console.log("Integrated Rashi context for sidebar chat:", sourceRef);
                }
              }
            }
          } finally {
            clearTimeout(timeoutId);
          }
        } catch (e) {
          console.log("Rashi fetch skipped or failed for sidebar chat.");
        }
      }

      const systemInstruction = `אתה 'ספרא' (Sefra), עוזר מחקר תורני מהיר ומדויק. 
תפקידך להסביר את המקור שהמשתמש מעיין בו כרגע בצורה בהירה ותמציתית.

חוקי המענה:
1. ענה מהר ולעניין. אל תאריך בהקדמות או בסיומות מיותרות.
2. אם מדובר בגמרא, עליך להתבסס בראש ובראשונה על פירוש רש"י (אם צורף לקונטקסט) ולהסביר את המהלך לפיו.
3. דייק בלשונך. השתמש במושגים ישיבתיים קצרמ"ים (למשל: 'ביאור הדברים', 'דאיתא', 'ופירש רש"י').
4. אל תמציא מקורות או מילים שלא קיימים.

${contextInfo}`;

      const formattedContents = history.map((msg: any) => ({
        role: msg.role === "user" ? "user" : "model",
        parts: [{ text: msg.content || "" }]
      }));
      formattedContents.push({ role: "user", parts: [{ text: message }] });

      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash", 
        contents: formattedContents,
        config: { 
          systemInstruction,
          temperature: 0.2,
          maxOutputTokens: 8192
        }
      });

      const usageMetadata = response.usageMetadata;
      const promptTokens = usageMetadata?.promptTokenCount || 0;
      const candidatesTokens = usageMetadata?.candidatesTokenCount || 0;
      const totalTokens = usageMetadata?.totalTokenCount || 0;
      const usdToIls = 3.7;
      const costUsd = ((promptTokens * 0.075) / 1000000) + ((candidatesTokens * 0.3) / 1000000);
      const costIls = costUsd * usdToIls;

      let responseText = "";
      for (const part of response.candidates?.[0]?.content?.parts || []) {
        if (part.text) responseText += part.text;
      }
      if (!responseText) responseText = response.text || "לא הצלחתי לגבש הסבר כרגע.";

      res.json({ 
        text: responseText,
        usage: {
          promptTokens,
          candidatesTokens,
          totalTokens,
          costUsd,
          costIls
        }
      });
    } catch (error: any) {
      console.error("Chat API error:", error);
      res.status(500).json({ error: error.message || "שגיאה בעיבוד הבקשה" });
    }
  });

  // API Route for generating images with halachic research and constraints
  app.post("/api/generate-image", async (req, res) => {
    try {
      const { prompt, apiKey } = req.body;
      if (!prompt) return res.status(400).json({ error: "Prompt is required" });

      const ai = getGeminiClient(apiKey);

      // --- STAGE 1: VISUAL RESEARCH (Gemini 3.5 Flash + Google Search) ---
      const researchSystemInstruction = `אתה 'חוקר ויזואלי תורני'. תפקידך לחקור לעומק כיצד מושג תורני אמור להיראות במדויק על פי התורה, חז"ל, והמפרשים. 
חובה עליך לערוך תחקיר מעמיק ביותר: עליך ללמוד ולחקור את כל פרטי הדינים של המושג מהיסודות הבסיסיים ביותר ועד לפרטים הקטנים ביותר!
לדוגמא: אם התבקשת ליצור תמונה של מנורת המקדש, עליך ללמוד עליה משלב הבסיס ועד לענפי ענפים וכל דיניה הוויזואליים. אם התבקשת ליצור תמונה של בגדי הכהן הגדול, עליך ללמוד איך המצנפת נראית, איך הציץ נראה מדוייק וכן כל שאר הבגדים, כל פרט הכי קטן! רק לאחר שחקרת לעומק, פתחת מקורות ויש לך תמונה ברורה, תגבש החלטה. עליך להשתמש ב-Google Search מרובה פעמים כדי לבסס היטב את תיאורך.
בסיום המחקר המעמיק, עליך לספק שני דברים:
1. "visualPrompt": תיאור ויזואלי מפורט מאוד באנגלית עבור מודל יצירת תמונה, המכיל את כל המסקנות מהמחקר המדוקדק שעשית, שום פרט שולי לא ייחסר (ללא נשים, ללא עבודה זרה, ללא פסלי אדם, וללא 4 דמויות המרכבה יחד).
2. "explanation": הסבר בעברית המפרט את הממצאים שלך עליהם מבוסס הציור ומהם המקורות לחזות הספציפית הזו.

חוקי ברזל:
- אין נשים.
- אין עבודה זרה/פסלים.
- אין 4 דמויות המרכבה (אדם, אריה, שור, נשר) בפריים אחד.
- הפרומפט באנגלית חייב להיות עשיר בפרטים (סגנון: photorealistic, 4k, cinematic lighting).

החזר את התשובה במבנה JSON בלבד.`;

      const researchResponse = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: [{ role: "user", parts: [{ text: `חקור ואייר את המושג: ${prompt}` }] }],
        config: {
          systemInstruction: researchSystemInstruction,
          tools: [{ googleSearch: {} } as any],
          responseMimeType: "application/json",
          responseSchema: {
            type: "OBJECT",
            properties: {
              visualPrompt: { type: "STRING" },
              explanation: { type: "STRING" }
            },
            required: ["visualPrompt", "explanation"]
          }
        }
      });

      const researchUsage = researchResponse.usageMetadata;

      let researchData;
      try {
        researchData = JSON.parse(researchResponse.text || "{}");
      } catch (e) {
        console.error("Failed to parse research JSON:", researchResponse.text);
        throw new Error("נכשלה מלאכת המחקר הוויזואלי.");
      }

      const { visualPrompt, explanation } = researchData;
      if (!visualPrompt) throw new Error("לא הצלחתי לגבש תיאור ויזואלי תקין.");

      // --- STAGE 2: DRAWING (Gemini 3.1 Flash Image Preview) ---
      const drawSystemInstruction = `אתה 'המאייר התורני'. תפקידך לצייר את הפרומפט שקיבלת בדיוק רב.
חוקי ברזל (אל תסטה מהם):
1. אין נשים.
2. אין עבודה זרה או פסלי אדם.
3. אין 4 דמויות המרכבה יחד.
סגנון: צילום היסטורי ריאליסטי, איכות גבוהה.`;

      const imageResponse = await ai.models.generateContent({
        model: "gemini-3.1-flash-image-preview",
        contents: [{ role: "user", parts: [{ text: visualPrompt }] }],
        config: {
          systemInstruction: drawSystemInstruction,
          imageConfig: {
            aspectRatio: "1:1",
            imageSize: "1K"
          }
        }
      });

      const drawUsage = imageResponse.usageMetadata;
      const totalPromptTokens = (researchUsage?.promptTokenCount || 0) + (drawUsage?.promptTokenCount || 0);
      const totalCandidatesTokens = (researchUsage?.candidatesTokenCount || 0) + (drawUsage?.candidatesTokenCount || 0);
      const totalTokens = (researchUsage?.totalTokenCount || 0) + (drawUsage?.totalTokenCount || 0);
      
      const usdToIls = 3.7;
      // Fixed cost for image generation + token costs for research
      const imageCostUsd = 0.03; 
      const researchCostUsd = ((researchUsage?.promptTokenCount || 0) * 0.075 / 1000000) + ((researchUsage?.candidatesTokenCount || 0) * 0.3 / 1000000);
      const costUsd = imageCostUsd + researchCostUsd;
      const costIls = costUsd * usdToIls;

      let imageData = null;
      if (imageResponse.candidates?.[0]?.content?.parts) {
        for (const part of imageResponse.candidates[0].content.parts) {
          if (part.inlineData) {
            imageData = part.inlineData.data;
            break;
          }
        }
      }

      if (!imageData) {
        throw new Error("לא הצלחתי ליצור את התמונה. ייתכן שהפרומפט חרג ממדיניות הבטיחות או המגבלות ההלכתיות.");
      }

      res.json({ 
        image: `data:image/png;base64,${imageData}`,
        explanation: (explanation || "הנה המחשה ויזואלית למה שביקשת.").trim(),
        usage: {
          promptTokens: totalPromptTokens,
          candidatesTokens: totalCandidatesTokens,
          totalTokens: totalTokens,
          costUsd,
          costIls
        }
      });

    } catch (error: any) {
      console.error("Image generation error:", error);
      res.status(500).json({ error: error.message || "שגיאה ביצירת התמונה" });
    }
  });

  // Proxy API Route for YouTube oEmbed
  app.get("/api/youtube-info", async (req, res) => {
    try {
      const { url } = req.query;
      if (!url || typeof url !== "string") {
        return res.status(400).json({ error: "No url provided" });
      }
      const fetchRes = await fetch(`https://noembed.com/embed?url=${encodeURIComponent(url)}`);
      if (!fetchRes.ok) {
        return res.status(fetchRes.status).json({ error: "Failed to fetch from noembed" });
      }
      const data = await fetchRes.json();
      res.json(data);
    } catch (e: any) {
      console.error("/api/youtube-info error:", e);
      res.status(500).json({ error: e.message || "Failed to fetch youtube details" });
    }
  });

  // Proxy API Route for Sefaria texts
  app.get("/ext/v1/load", async (req, res) => {
    try {
      const { ref, context, translation } = req.query;
      if (!ref || typeof ref !== "string") {
        return res.status(400).json({ error: "No ref provided" });
      }
      
      const queryParams = new URLSearchParams();
      if (context) queryParams.set("context", String(context));
      if (translation) queryParams.set("translation", String(translation));
      
      const refStr = String(ref).trim();
      let data: any = null;
      let response: Response | null = null;
      
      const fetchHeaders = {
        "User-Agent": "SefraTorahResearch/1.0 (https://ai.studio/build; ikarpel100@gmail.com) Mozilla/5.0",
        "Accept": "application/json"
      };

      const trySefaria = async (r: string) => {
        let normalized = r
          .replace(/\s+/g, "_")
          .replace(/_+/g, "_")
          .replace(/,_+/g, ",_")
          .replace(/,([^_])/g, ",_$1");

        const encodedRef = normalized.split("").map(c =>
          (c === "," || c === "." || c === "_" ||
           (c >= "a" && c <= "z") || (c >= "A" && c <= "Z") ||
           (c >= "0" && c <= "9") || c === "-")
            ? c : encodeURIComponent(c)
        ).join("");

        let url = `https://www.sefaria.org/api/texts/${encodedRef}?${queryParams.toString()}`;
        console.log("Backend proxying Sefaria:", url);
        
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 15000);
        
        try {
          const res = await fetch(url, { headers: fetchHeaders, signal: controller.signal });
          if (res.ok) {
            const textData = await res.text();
            try {
              const parsed = JSON.parse(textData);
              if (parsed && parsed.he && (!Array.isArray(parsed.he) || parsed.he.length > 0)) {
                return { ok: true, data: parsed, response: res };
              }
            } catch (e) {}
          }
          return { ok: false, status: res.status };
        } finally {
          clearTimeout(timeoutId);
        }
      };

      try {
        let result = await trySefaria(refStr);
        if (result.ok) {
          data = result.data;
          response = result.response;
        } else {
          // Alternative 1: Chaim -> Chayim
          if (refStr.includes("Chaim")) {
            console.log("Sefaria 'Chaim' failed, trying 'Chayim' variation...");
            const altResult = await trySefaria(refStr.replace(/Chaim/g, "Chayim"));
            if (altResult.ok) {
              data = altResult.data;
              response = altResult.response;
            }
          }
          
          // Alternative 2: Replace comma with dot (some refs are indexed this way)
          if (!data) {
            const dottedResult = await trySefaria(refStr.replace(/,/g, "."));
            if (dottedResult.ok) {
              data = dottedResult.data;
              response = dottedResult.response;
            }
          }

          // Alternative 3: Specific fix for Shulchan Arukh HaRav
          if (!data && refStr.toLowerCase().includes("rav")) {
             const ravFix = refStr.replace(/Rav[,.]\s*/i, "HaRav, ");
             const ravResult = await trySefaria(ravFix);
             if (ravResult.ok) {
               data = ravResult.data;
               response = ravResult.response;
             }
          }

          // Alternative 4: Broaden Rashi/Rashbam if segment fetch failed
          if (!data && (refStr.toLowerCase().includes("rashi") || refStr.toLowerCase().includes("rashbam"))) {
            console.log("Sefaria Rashi/Rashbam specific segment failed, attempting to broaden ref...");
            // Talmud: Rashi_on_Niddah.23a.11 -> Rashi_on_Niddah.23a
            let broadRef = refStr;
            const talmudMatch = refStr.match(/^(.*?[._\s][0-9]+[ab])([:.\s_]+[0-9]+)*$/i);
            if (talmudMatch) {
              broadRef = talmudMatch[1];
            } else {
              // Tanakh: Rashi_on_Genesis.1.1.1 -> Rashi_on_Genesis.1.1
              const parts = refStr.split(/[:.\s_]+/);
              if (parts.length > 4) {
                broadRef = parts.slice(0, 5).join(".");
              }
            }
            
            if (broadRef !== refStr) {
               console.log(`Trying broadened Rashi ref: ${broadRef}`);
               const broadResult = await trySefaria(broadRef);
               if (broadResult.ok) {
                 data = broadResult.data;
                 response = broadResult.response;
               }
            }
          }
        }
      } catch (sefariaErr) {
        console.error("Internal Sefaria fetch failed:", sefariaErr);
      }
      
      // Fallback to secondary Sefaria domain if primary failed
      if (!response || !response.ok || !data || !data.he || (Array.isArray(data.he) && data.he.length === 0)) {
        console.log("Primary Sefaria failed or empty, trying fallback for:", refStr);
        try {
          // Re-encode for fallback
          let normalized = refStr
            .replace(/\s+/g, "_")
            .replace(/_+/g, "_")
            .replace(/,_+/g, ",_")
            .replace(/,([^_])/g, ",_$1");

          const encodedRef = normalized.split("").map(c =>
            (c === "," || c === "." || c === "_" ||
             (c >= "a" && c <= "z") || (c >= "A" && c <= "Z") ||
             (c >= "0" && c <= "9") || c === "-")
               ? c : encodeURIComponent(c)
          ).join("");

          const fallbackUrl = `https://sefaria.org/api/texts/${encodedRef}?context=0`;
          console.log("Backend proxying fallback Sefaria:", fallbackUrl);

          const fallbackController = new AbortController();
          const fallbackTimeoutId = setTimeout(() => fallbackController.abort(), 12000);

          try {
            const fallbackRes = await fetch(fallbackUrl, { headers: fetchHeaders, signal: fallbackController.signal });
            if (fallbackRes.ok) {
              const textData = await fallbackRes.text();
              const parsed = JSON.parse(textData);
              if (parsed && parsed.he && (!Array.isArray(parsed.he) || parsed.he.length > 0)) {
                return res.json(parsed);
              }
            }
          } finally {
            clearTimeout(fallbackTimeoutId);
          }
        } catch (fallbackErr) {
          console.error("Fallback Sefaria failed:", fallbackErr);
        }
      }
      
      if (response && response.ok && data) {
         return res.json(data);
      }
      
      res.status(response ? response.status : 500).json(data || { error: "מקור לא נמצא במאגר" });
    } catch (error: any) {
      console.error("Proxy Sefaria API request fail:", error);
      res.status(500).json({ error: error.message || "שגיאה בטעינת המקור" });
    }
  });

  // AI Assistant endpoint to find exact substring match for a quote in a large text
  app.post("/ext/v1/match", async (req, res) => {
    console.log("Entering /ext/v1/match handler");
    try {
      const { text, quote, apiKey } = req.body;
      if (!text || !quote) {
        console.log("Match failed: missing text or quote");
        return res.status(400).json({ error: "Text and quote are required" });
      }

      console.log(`Matching quote (len: ${quote.length}) against text (len: ${text.length})`);
      const ai = getGeminiClient(apiKey);
      
      const prompt = `אתה בוט שתפקידו לאתר במדויק ציטוט מתוך טקסט מקור (כמו גמרא או רמב"ם).
המשתמש מחפש מחרוזת (ציטוט) מסוימת. המטרה שלך היא למצוא את החלק בטקסט המקור שתואם את הציטוט המבוקש בדיוק מילה במילה, ולהחזיר אך ורק את החלק הזה כפי שהוא מופיע במקור (כולל הניקוד והמילים המדויקות כפי שהן שם).
חשוב מאוד: אל תחזיר את כל המשפט או הפיסקה! אם הציטוט המקורי היה קטע קצר (כגון "אמר ליה: איני יכול, מפני שהוא אוכל מעשר"), עליך למצוא רק את אוסף המילים התואמות לו במקור (למשל "אֲמַר לֵיהּ. לֵית אֲנָא יְכִיל. אֲמַר לֵיהּ. לָמָּה. אֲמַר לֵיהּ. דַּאֲנָא אֲכִל מַעֲשֵׂר.") ולהחזיר אך ורק אותן.

טקסט המקור המלא:
---
${text}
---

הציטוט להשוות ולחפש (הציטוט המבוקש):
---
${quote}
---

חובה: החזר אך ורק את חלק הטקסט המדויק מתוך המקור שתואם בדיוק לציטוט שביקש המשתמש. לא להוסיף הסברים, מרכאות או שום מילה משלך. רק המילים הספציפיות המדויקות מהמקור שמהוות את הציטוט.`;

      let aiResponse = await ai.models.generateContent({
        model: "gemini-1.5-flash-8b",
        contents: [{ role: "user", parts: [{ text: prompt }] }],
        config: {
          temperature: 0.1,
        }
      });
      
      const result = aiResponse.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || aiResponse.text?.trim() || null;
      console.log("Match result found:", result ? `Yes (len: ${result.length})` : "No");

      const usageMetadata = aiResponse.usageMetadata;
      const usdToIls = 3.7;
      const costUsd = (((usageMetadata?.promptTokenCount || 0) * 0.075) / 1000000) + (((usageMetadata?.candidatesTokenCount || 0) * 0.3) / 1000000);
      
      res.json({ 
        exactQuote: result,
        usage: {
          promptTokens: usageMetadata?.promptTokenCount || 0,
          candidatesTokens: usageMetadata?.candidatesTokenCount || 0,
          totalTokens: usageMetadata?.totalTokenCount || 0,
          costUsd,
          costIls: costUsd * usdToIls
        }
      });
    } catch (e: any) {
       console.error("Find exact quote failed:", e);
       res.status(500).json({ error: e.message || "שגיאה בחיפוש ציטוט מדויק" });
    }
  });

  // API Route for health and status checking
  app.get("/ext/v1/status", (req, res) => {
    res.json({ status: "ok", message: "Server is healthy", timestamp: new Date().toISOString() });
  });

  // API Route for generating a short chat title
  app.post("/ext/v1/title", async (req, res) => {
    try {
      const { message, apiKey } = req.body;
      if (!message) return res.status(400).json({ error: "Message is required" });

      const ai = getGeminiClient(apiKey);
      
      const prompt = `אתה עוזר חכם המייצר כותרות קצרות וקולעות לשיחות. 
ההודעה הראשונה של המשתמש היא: "${message}"
ייצר כותרת קצרה מאוד (עד 5 מילים) בעברית שמתארת את נושא השיחה המרכזי. 
אל תשתמש במרכאות, אל תוסיף נקודה בסוף, ואל תכתוב שום דבר מלבד הכותרת עצמה.`;

      const response = await ai.models.generateContent({
        model: "gemini-3.5-flash",
        contents: prompt
      });
      
      const title = response.text?.trim() || "שיחה חדשה";
      const usageMetadata = response.usageMetadata;
      const usdToIls = 3.7;
      const costUsd = (((usageMetadata?.promptTokenCount || 0) * 0.075) / 1000000) + (((usageMetadata?.candidatesTokenCount || 0) * 0.3) / 1000000);

      res.json({ 
        title,
        usage: {
          promptTokens: usageMetadata?.promptTokenCount || 0,
          candidatesTokens: usageMetadata?.candidatesTokenCount || 0,
          totalTokens: usageMetadata?.totalTokenCount || 0,
          costUsd,
          costIls: costUsd * usdToIls
        }
      });
    } catch (error) {
      console.error("Title generation error:", error);
      res.json({ title: null });
    }
  });

  // API Route for grounded chat requests
  app.post("/ext/v1/process", async (req, res) => {
    try {
      const { 
        message, 
        history = [], 
        model = "gemini-3.5-flash", 
        attachment, 
        answerStyle = "neutral",
        personalSettings 
      } = req.body;

      if (!message || typeof message !== "string") {
        return res.status(400).json({ error: "Message parameter is required." });
      }

      // 1. Initialize API Client safely
      const ai = getGeminiClient(personalSettings?.apiKey);

      // 2. Format history to fit the strict structure
      const formattedContents = history.map((msg: any) => {
        const parts: any[] = [{ text: msg.text || "" }];
        
        // Handle physical file attachments (legacy or current)
        const msgAttachments = [];
        if (msg.attachments && Array.isArray(msg.attachments)) {
          msgAttachments.push(...msg.attachments);
        } else if (msg.attachment) {
          msgAttachments.push(msg.attachment);
        }

        msgAttachments.forEach((att: any) => {
          if (att.data) {
            parts.push({
              inlineData: {
                data: att.data,
                mimeType: att.mimeType || "application/octet-stream",
              },
            });
          } else if (att.url && att.type === "youtube") {
            parts.push({
              fileData: {
                fileUri: att.url,
                mimeType: "video/mp4"
              }
            });
          }
        });
        
        return {
          role: msg.role === "user" ? "user" : "model",
          parts,
        };
      });

      // Append current message
      const currentParts: any[] = [{ text: message }];
      
      // Handle attachments in current message
      const attachments = req.body.attachments || (req.body.attachment ? [req.body.attachment] : []);
      attachments.forEach((att: any) => {
        if (att.data) {
          currentParts.push({
            inlineData: {
              data: att.data,
              mimeType: att.mimeType || "application/octet-stream",
            },
          });
        } else if (att.url && att.type === "youtube") {
          currentParts.push({
            fileData: {
              fileUri: att.url,
              mimeType: "video/mp4"
            }
          });
        }
      });

      // Also detect YouTube URLs in the message text itself if not explicitly attached
      const ytMatch = message.match(/(?:https?:\/\/)?(?:www\.)?(?:youtube\.com\/watch\?v=|youtu\.be\/)([a-zA-Z0-9_-]{11})/);
      if (ytMatch && (!attachment || (attachment.type !== "youtube" && !attachment.data))) {
        currentParts.push({
          fileData: {
            fileUri: ytMatch[0],
            mimeType: "video/mp4"
          }
        });
      }

      formattedContents.push({
        role: "user",
        parts: currentParts,
      });

      // 3. Select Gemini model
      const modelToUse = "gemini-3.5-flash"; // Force Flash as requested

      let lengthInstruction = "";
      if (answerStyle === "short") {
        lengthInstruction = "\nסגנון מענה: קצר ותמציתי. ענה לעניין בלי מאריכים ובלי פלפולים מיותרים. הבא רק את המקור המדויק ביותר.";
      } else if (answerStyle === "detailed") {
        lengthInstruction = "\nסגנון מענה: ארוך ומעמיק ככל הניתן! מפלפל מאוד, רב-מקורות ומפורט להפליא. דון בסוגיה לעומק, הרחב בכל הצדדים שלה, והסבר כל תת-נושא באופן יסודי וארוך. הקפד לשלב כמה שיותר מקורות רלוונטיים ומדויקים (מבלי לדחוף סתם דברים לא קשורים, הכול בגדר הטעם הטוב), כדי שהתשובה תהיה עשירה, ענקית ומלאה בתוכן מחקרי ותורני איכותי. אל תחסוך במידע.";
      } else {
        lengthInstruction = "\nסגנון מענה: בינוני ורגיל. הסבר את הסוגיה בצורה ברורה ומקיפה בלוויית המקורות הרלוונטיים.";
      }

      let personalInfoInstruction = "";
      if (personalSettings) {
        if (personalSettings.aboutMe) {
          personalInfoInstruction += `\nמידע על המשתמש: ${personalSettings.aboutMe}`;
        }
        if (personalSettings.halakhicAuthority && personalSettings.halakhicAuthority !== 'neutral') {
          const authorityMap: Record<string, string> = {
            'mizrach': 'עדות המזרח (הרב עובדיה יוסף)',
            'sefard': 'ספרד (בית יוסף)',
            'ashkenaz': 'אשכנז (רמ"א / משנה ברורה)',
            'yemen': 'תימנים (השרע"בי / הרב קאפח)',
            'chabad': 'חב"ד (אדמו"ר הזקן / הרבי מלובביץ\')'
          };
          personalInfoInstruction += `\nהעדפת פסיקה/מסורת: ${authorityMap[personalSettings.halakhicAuthority] || personalSettings.halakhicAuthority}. עליך להציע תשובות המשתלבות עם גישה זו במידת האפשר, אך תמיד לציין אם יש דעות חולקות מהותיות.`;
        }
        if (personalSettings.customInstructions) {
          personalInfoInstruction += `\nהנחיות אישיות מהמשתמש: ${personalSettings.customInstructions}`;
        }
      }

      const systemInstruction = `אתה 'ספרא' (Sefra), עוזר מחקר תורני מומחה. ${personalInfoInstruction}
חוק הברזל: אמת ודיוק אבסולוטי. אסור בתכלית האיסור להמציא מקורות, ספרים, או ציטוטים. 
עליך לוודא שהציטוטים שאתה כותב מדויקים מילה במילה (מילה במילה בול!), ללא שינוי של אות אחת, ללא חרטוטים, הוספת מילים או השמטת מילים. הדיוק הוא מעל הכל.
עדיף לומר "איני יודע" מאשר להשיב תשובה שגויה או לצטט מקור לא קיים.

הנחיה לוגית קריטית: על כל מהלך, פלפול או הסבר הלכתי להתבסס אך ורק על 'היגיון בריא' וישר (הגיון ברזל). הימנע לחלוטין מסברות עקומות, מאולצות או כאלו שאין בהן שמץ של הגיון פשוט ומקובל. המהלך הלוגי חייב להיות מוצק, ברור ומתקבל על הדעת.

${lengthInstruction}

פרוטוקול בדיקה לפני מענה:
1. וודא שכל מראה מקום (Referencing) קיים במציאות.
2. חובה קריטית ואבסולוטית: עבור כל מקור שאתה מציין, עליך להביא את הציטוט המלא מילה במילה (מילה במילה!) מהספר. אל תסתפק במראה מקום בלבד. אל תחרטט ואל תוסיף מילים לציטוט. העתק את לשון המקור בדיוק מושלם.
3. הפרדה מלאה: הציטוט המלא חייב להופיע בתוך Blockquote (>) בנפרד מההסברים שלך. אל תשלב מילים שלך בתוך הציטוט.
4. וודא שציטוטים הם "מילה במילה" מהמקור. אם אינך בטוח ב-100%, השתמש בחיפוש גוגל לאימות המקור.
5. סגנון ישיבתי-לימודי רציני ומעמיק.

מבנה התשובה:
- השתמש ב-[SefariaRef: URL_Slug|Exact_Quote|Hebrew_Name] עבור כל מקור.
- חובה: ה-Hebrew_Name בשדה התגית חייב להיות בעברית בלבד (ללא אנגלית בכלל!). למשל: [SefariaRef: Shabbat.2a|יציאות השבת שתים שהן ארבע|שבת ב' א'].
- חשוב ביותר: עליך למלא את שדה ה-Exact_Quote בתוך התגית בטקסט המדויק והמלא של המקור מילה במילה (בדיוק מושלם!).
- ציטוטים ישירים יופיעו אך ורק ב-Blockquote (>).
- כל הסבר, פרשנות או דברי ה-AI יופיעו מחוץ לציטוט ובנפרד ממנו.
- חובה עליך להוסיף בחתימת דבריך/בסוף התשובה משפט קצר: "אין לקחת פסיקה זו כהלכה למעשה ויש להתייעץ עם רב מוסמך."`;

      const genConfig = {
        systemInstruction,
        temperature: 0.1, // Extreme precision
        tools: [
          { googleSearch: {} } as any,
          {
            functionDeclarations: [
              {
                name: "count_text_occurrences",
                description: "סופר כמה פעמים מופיע ביטוי מסוים במסכת או בספר כלשהו. חובה להשתמש בזה לכל שאלת ספירה מדויקת.",
                parameters: {
                  type: "OBJECT",
                  properties: {
                    book: { type: "STRING", description: "שם הספר או המסכת באנגלית לפי ספריא (למשל: Berakhot, Shabbat, Genesis)" },
                    phrase: { type: "STRING", description: "הביטוי המדויק בעברית לחיפוש (למשל: תנו רבנן)" }
                  },
                  required: ["book", "phrase"]
                }
              }
            ]
          }
        ],
        toolConfig: {
          includeServerSideToolInvocations: true
        } as any,
      };

      // 4. Generate Content with Grounding and Tool Calls loop
      let response;
      let generateRetries = 0;
      const maxGenerateRetries = 1;

      while (generateRetries <= maxGenerateRetries) {
        try {
          response = await ai.models.generateContent({
            model: modelToUse,
            contents: formattedContents,
            config: genConfig,
          });
          break;
        } catch (err: any) {
          const isTimeout = err.status === "DEADLINE_EXCEEDED" || err.message?.includes("DEADLINE_EXCEEDED") || err.message?.includes("504");
          if (isTimeout && generateRetries < maxGenerateRetries) {
            console.warn(`Gemini 504 detected, retrying first stage... (${generateRetries + 1}/${maxGenerateRetries})`);
            generateRetries++;
            continue;
          }
          throw err;
        }
      }

      if (!response) throw new Error("Failed to get response from AI after retries.");

      // Handle function calls if any
      while (response.functionCalls && response.functionCalls.length > 0) {
        const call = response.functionCalls[0];
        if (call.name === "count_text_occurrences") {
          const args = call.args as { book: string, phrase: string };
          let countResult: number | string = "Error: unknown";
          try {
            console.log(`Tool executing: counting ${args.phrase} in ${args.book}`);
            const sefariaRes = await fetch(`https://www.sefaria.org/api/v3/texts/${encodeURIComponent(args.book.trim())}`);
            const data = await sefariaRes.json();
            const hebVersion = data.versions ? data.versions.find((v: any) => v.language === "he" || v.actualLanguage === "he") : undefined;
            if (hebVersion) {
              let str = JSON.stringify(hebVersion.text || "");
              const cleanString = (s: string) => s.replace(/[^\u05D0-\u05EA\s]/g, ""); // strip niqqud and punctuation
              const cleanedRaw = cleanString(str).replace(/\s+/g, " ");
              const cleanedPhrase = cleanString(args.phrase).replace(/\s+/g, " ").trim();
              const count = cleanedRaw.split(cleanedPhrase).length - 1;
              countResult = count;
            } else {
              countResult = "Error: Hebrew text not found for book: " + args.book;
            }
          } catch (e: any) {
             console.error("Sefaria plugin error:", e);
             countResult = "Error parsing text: " + e.message;
          }

          formattedContents.push({
            role: "model",
            parts: response.candidates?.[0]?.content?.parts || [{ functionCall: call }],
          });
          formattedContents.push({
            role: "user",
            parts: [{
              functionResponse: {
                name: call.name,
                response: { count: countResult }
              }
            }],
          });

          response = await ai.models.generateContent({
            model: modelToUse,
            contents: formattedContents,
            config: genConfig,
          });
        } else {
          break;
        }
      }

      // Collect all text parts from the response (avoids "non-text parts" SDK warning)
      let responseText = "";
      const candidateParts = response.candidates?.[0]?.content?.parts || [];
      for (const part of candidateParts) {
        if (part.text) responseText += part.text;
      }
      if (!responseText) responseText = response.text || "";

      const usageMetadata = response.usageMetadata;
      const usdToIls = 3.7;
      const costUsd = (((usageMetadata?.promptTokenCount || 0) * 0.075) / 1000000) + (((usageMetadata?.candidatesTokenCount || 0) * 0.3) / 1000000);

      // --- AI PROOFREADER / VERIFIER STAGE ---
      // Skip proofreader if response has no SefariaRef tags (nothing to verify) or is very short.
      // This dramatically reduces timeout occurrences on simple responses.
      const hasSefariaRefs = responseText.includes("[SefariaRef:");
      const isLongEnoughToVerify = responseText.length > 300;
      if (hasSefariaRefs && isLongEnoughToVerify) try {
        const verifierSystemInstruction = `אתה 'המגיה התורני' (The Torah Proofreader). תפקידך לאמת ולדייק את התשובה שכתב עוזר AI אחר (ספרא).
תפקידך הקריטי: וודא שכל מראה מקום (Referencing) מלווה בציטוט מלא, מדויק מילה במילה (בדיוק מושלם!), שנמצא בתוך Blockquote נפרד. 
אל תחרטט, אל תוסיף מילים, אל תשנה מילים ואל תחליף מילים נרדפות. הציטוט חייב להיות נאמן למקור ב-100% (מילה במילה בול!).

וודא שני דברים נוספים:
1. שמות המקורות (Hebrew_Name) בתוך תגיות [SefariaRef:...] הם בעברית בלבד. אם מופיעה אנגלית, תרגם אותה לעברית תקנית.
2. המהלך הלוגי בתשובה הוא ישר ומבוסס על 'היגיון בריא'. אם זיהית סברות עקומות או מאולצות שאינן מתקבלות על הדעת, תקן את הניסוח כך שיהיה הגיוני וברור.

חוקי שימור והפרדה:
1. הפרדה מוחלטת: אסור שיהיה ערבוב של דברי ה-AI בתוך הציטוט. הציטוט ב-Blockquote חייב להכיל אך ורק את לשון המקור כפי שהיא.
2. וודא שפורמט מראי המקומות נשמר ומולא כראוי: [SefariaRef: URL_Slug|Exact_Quote|Hebrew_Name]. שדה ה-Exact_Quote חייב לצטט את המקור במדויק מילה במילה (בדיוק מושלם!).
3. שמור על הסגנון המקורי של ספרא, אך אל תתפשר על דיוק הציטוטים.
4. הציטוט חייב להיות נאמן לטקסט המקורי של הספר.

אם מצאת טעויות או ציטוטים לא מדויקים:
- תקן את הטעויות בגוף הטקסט. וודא שהציטוטים מלאים ומדויקים מילה במילה בול.
- החזר את התשובה המתוקנת והמדויקת בלבד.

אם התשובה המקורית מדויקת ב-100% ואין בה שום טעות עובדתית או ציטוטי:
- החזר את התשובה המקורית בדיוק כפי שהיא (BUBBLE_COPY_OK).

חשוב: אל תוסיף הקדמות כמו "תיקנתי את..." או "הנה התשובה...". פשוט פלט את התוכן הסופי.`;

        const verifierParts: any[] = [
          { text: `הנה התשובה שעליך להגיה ולאמת עבור השאלה: "${message}"\n\nהתשובה:\n${responseText}` }
        ];

        // Include attachments for the proofreader
        attachments.forEach((att: any) => {
          if (att.data) {
            verifierParts.push({
              inlineData: {
                data: att.data,
                mimeType: att.mimeType || "application/octet-stream",
              },
            });
          }
        });

        const verificationResponse = await Promise.race([
          ai.models.generateContent({
            model: "gemini-3.5-flash", 
            contents: [
              { role: "user", parts: verifierParts }
            ],
            config: {
              systemInstruction: verifierSystemInstruction,
              temperature: 0.1,
              // Removed googleSearch from proofreader to prevent timeout cascades.
              // The proofreader verifies format/structure only; grounding is done in the main stage.
            }
          }),
          new Promise<any>((_, reject) => setTimeout(() => reject(new Error("Proofreader timeout")), 90000))
        ]);

        if (verificationResponse && verificationResponse.text) {
          const verifiedText = verificationResponse.text.trim();
          if (verifiedText && !verifiedText.includes("BUBBLE_COPY_OK") && verifiedText !== responseText) {
            responseText = verifiedText;
          }

          // Accumulate proofreader cost
          const vUsage = verificationResponse.usageMetadata;
          if (vUsage && usageMetadata) {
            usageMetadata.promptTokenCount = (usageMetadata.promptTokenCount || 0) + (vUsage.promptTokenCount || 0);
            usageMetadata.candidatesTokenCount = (usageMetadata.candidatesTokenCount || 0) + (vUsage.candidatesTokenCount || 0);
            usageMetadata.totalTokenCount = (usageMetadata.totalTokenCount || 0) + (vUsage.totalTokenCount || 0);
          }
        }
      } catch (verErr: any) {
        console.error("Proofreader stage failed:", verErr);
      } // end if hasSefariaRefs

      const groundingMetadata = response.candidates?.[0]?.groundingMetadata || null;

      const finalCostUsd = (((usageMetadata?.promptTokenCount || 0) * 0.075) / 1000000) + (((usageMetadata?.candidatesTokenCount || 0) * 0.3) / 1000000);

      return res.json({
        text: responseText,
        groundingMetadata,
        usage: {
          promptTokens: usageMetadata?.promptTokenCount || 0,
          candidatesTokens: usageMetadata?.candidatesTokenCount || 0,
          totalTokens: usageMetadata?.totalTokenCount || 0,
          costUsd: finalCostUsd,
          costIls: finalCostUsd * usdToIls
        }
      });

    } catch (error: any) {
      console.error("Gemini API Error details:", error);
      const isApiKeyMissing = error.message?.includes("GEMINI_API_KEY");
      
      const statusCode = mapErrorToStatus(error);

      if (statusCode === 429) {
        return res.status(429).json({
          status: "quota_exceeded",
          error: "חריגה ממכסת השימוש ב-Gemini API (שגיאה 429).",
          message: "חרגת ממכסת השימוש הזמינה בנוכחית של מפתח ה-API שלך ב-Gemini. אנא המתן מעט או השתמש במודל Flash.",
          details: error.message || error.toString()
        });
      }

      if (statusCode === 504) {
        return res.status(504).json({
          status: "timeout",
          error: "זמן ההמתנה לתשובה מה-AI חרג מהמותר (504 DEADLINE_EXCEEDED).",
          message: "תהליך המחקר והביסוס לקח זמן רב מדי. ייתכן שהשאלה מורכבת מאוד או ששרתי גוגל עמוסים.",
          details: error.message || error.toString()
        });
      }

      return res.status(500).json({
        error: isApiKeyMissing
          ? "GEMINI_API_KEY is not configured. Please add it to your secrets panel."
          : error.message || "An unexpected error occurred while communicating with Gemini.",
        code: error.status || error.statusCode || "UNKNOWN",
        details: error.stack || error.toString(),
      });
    }
  });

  // Supabase proxy routes to handle "Failed to fetch" browser limit issues
  const SUPABASE_URL = "https://cyfjuytxqpjnntnvbblw.supabase.co";
  const SUPABASE_KEY = "sb_publishable_foKh65QDiTCPHw-nSRQC8w_9jet7mhf";
  const supabase = createClient(SUPABASE_URL, SUPABASE_KEY);

  app.post("/api/supabase/upsert", async (req, res) => {
    try {
      const { payload } = req.body;
      if (!payload) return res.status(400).json({ error: "No payload provided" });

      console.log("[Server-Supabase] Upserting for user:", payload.username);
      const { data, error } = await supabase
        .from('user_data')
        .upsert(payload, { onConflict: 'username' })
        .select();

      if (error) {
        console.error("[Server-Supabase] Upsert error:", error);
        return res.status(500).json({ error: error.message, details: error.details });
      }

      res.json({ success: true, data });
    } catch (err: any) {
      console.error("[Server-Supabase] Upsert exception:", err);
      res.status(500).json({ error: err.message || err });
    }
  });

  app.get("/api/supabase/fetch", async (req, res) => {
    try {
      const { username } = req.query;
      if (!username || typeof username !== "string") {
        return res.status(400).json({ error: "Username is required" });
      }

      console.log("[Server-Supabase] Fetching user:", username);
      const { data, error } = await supabase
        .from('user_data')
        .select('*')
        .eq('username', username.trim().toLowerCase())
        .single();

      if (error && error.code !== "PGRST116") { // Skip "no rows found" error
        console.error("[Server-Supabase] Fetch error:", error);
        return res.status(500).json({ error: error.message });
      }

      res.json({ data });
    } catch (err: any) {
      console.error("[Server-Supabase] Fetch exception:", err);
      res.status(500).json({ error: err.message || err });
    }
  });

  // Vite integration middleware
  if (process.env.NODE_ENV !== "production") {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: "spa",
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), "dist");
    app.use(express.static(distPath));
    app.get("*", (req, res) => {
      res.sendFile(path.join(distPath, "index.html"));
    });
  }

  app.listen(PORT, "0.0.0.0", () => {
    console.log(`Express server successfully initialized on http://localhost:${PORT}`);
  });
}

startServer();
